/**
 * Feature decomposition — splits a feature into atomic build parts
 * before generation. Each part is a narrow, focused generation unit
 * that succeeds or fails independently.
 *
 * Instead of one giant "generate settings page" LLM call, the builder
 * decomposes into: page-shell → auth-guard → form-body → mutation → validation → test.
 * Each part has a fixed preamble and produces a code fragment.
 * Fragments compose into final files.
 */
// ─── Fixed preambles (deterministic, no LLM) ────────────────────────
function authGuardPreamble(featureLabel) {
    return `  const { orgId, userId } = useAuth();

  if (!orgId) {
    return <div className="p-6 text-muted-foreground">Select an organization to continue.</div>;
  }
`;
}
function pageShellPreamble(featureLabel, featureSlug, imports) {
    const uniqueImports = [...new Set(imports)];
    return `"use client";

${uniqueImports.join("\n")}

/**
 * ${featureLabel}
 * Generated by AES — decomposed build
 */
export default function ${toPascalCase(featureSlug)}Page() {
`;
}
function loadingStatePreamble() {
    return `  if (items === undefined) {
    return (
      <div className="p-6">
        <div className="animate-pulse space-y-3">
          {[1, 2, 3].map((i) => (
            <div key={i} className="h-12 bg-muted rounded" />
          ))}
        </div>
      </div>
    );
  }

  if (items.length === 0) {
    return (
      <div className="p-6 text-center text-muted-foreground">
        <p className="text-lg mb-2">No items yet</p>
        <p>Create your first item to get started.</p>
      </div>
    );
  }
`;
}
function queryPreamble(tableName) {
    return `import { query } from "../_generated/server";
import { v } from "convex/values";

`;
}
function mutationPreamble(tableName) {
    return `import { mutation } from "../_generated/server";
import { v } from "convex/values";

`;
}
function testPreamble(featureSlug) {
    return `import { describe, it, expect, vi } from "vitest";

vi.mock("convex/react", () => ({
  useQuery: vi.fn(() => []),
  useMutation: vi.fn(() => vi.fn()),
}));
vi.mock("@clerk/nextjs", () => ({
  useAuth: vi.fn(() => ({ orgId: "org_test", userId: "user_test" })),
}));

`;
}
// ─── Helpers ─────────────────────────────────────────────────────────
function toPascalCase(str) {
    return str
        .split(/[-_\s]+/)
        .map((s) => s.charAt(0).toUpperCase() + s.slice(1))
        .join("");
}
function toSlug(name) {
    return name.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");
}
function capabilityIsForm(cap) {
    const lower = cap.toLowerCase();
    return lower.includes("form") || lower.includes("submit") || lower.includes("create") || lower.includes("edit");
}
function capabilityIsList(cap) {
    const lower = cap.toLowerCase();
    return lower.includes("list") || lower.includes("queue") || lower.includes("table") || lower.includes("history");
}
function capabilityIsDetail(cap) {
    const lower = cap.toLowerCase();
    return lower.includes("detail") || lower.includes("view") || lower.includes("review");
}
// ─── Decomposition ──────────────────────────────────────────────────
/**
 * Decompose a feature into atomic build parts.
 * Returns an ordered list of parts, each with a narrow prompt scope.
 */
export function decomposeFeature(pkg, context) {
    const featureSlug = toSlug(pkg.feature_name);
    const tableName = featureSlug.replace(/-/g, "_");
    const featureLabel = pkg.feature_name;
    const parts = [];
    const fileMap = {};
    // ── 1. Convex query (always needed) ──
    const queryFile = `convex/${featureSlug}/queries.ts`;
    parts.push({
        kind: "query",
        targetFile: queryFile,
        order: 0,
        prompt: `Generate Convex query functions for "${featureLabel}".
Table name: "${tableName}".
Required: list query filtered by orgId, get query by id + orgId.
Both must have args: { ... } with typed validators, returns: validator, and handler.
Use .withIndex("by_org", (q: any) => q.eq("orgId", args.orgId)) for the list query.
Output ONLY the function code (no imports, those are prepended).`,
        preamble: queryPreamble(tableName),
        deterministic: false,
        dependsOn: [],
    });
    fileMap[queryFile] = ["query"];
    // ── 2. Convex mutation (always needed) ──
    const mutationFile = `convex/${featureSlug}/mutations.ts`;
    parts.push({
        kind: "mutation",
        targetFile: mutationFile,
        order: 0,
        prompt: `Generate Convex mutation functions for "${featureLabel}".
Table name: "${tableName}".
Required: create mutation (insert with orgId, createdBy, createdAt, updatedAt), updateStatus mutation (patch with orgId ownership check).
Both must have args: { ... } with typed validators, returns: validator, and handler.
Output ONLY the function code (no imports, those are prepended).`,
        preamble: mutationPreamble(tableName),
        deterministic: false,
        dependsOn: [],
    });
    fileMap[mutationFile] = ["mutation"];
    // ── 3. Pages — decomposed per capability ──
    for (const cap of pkg.included_capabilities) {
        let capSlug = cap.toLowerCase().replace(/[^a-z0-9]+/g, "-");
        // Prevent path doubling when capability slug overlaps with feature slug
        if (capSlug === featureSlug || capSlug.startsWith(`${featureSlug}-`) || featureSlug.startsWith(`${capSlug}-`)) {
            if (capabilityIsForm(cap)) {
                capSlug = "new";
            }
            else if (capabilityIsDetail(cap)) {
                capSlug = "view";
            }
            else {
                capSlug = "list";
            }
        }
        if (capabilityIsForm(cap)) {
            const pagePath = `app/${featureSlug}/${capSlug}/page.tsx`;
            const pageParts = [];
            // 3a. Page shell (deterministic)
            parts.push({
                kind: "page-shell",
                targetFile: pagePath,
                order: 0,
                prompt: "",
                preamble: pageShellPreamble(featureLabel, `${featureSlug}-${capSlug}`, [
                    'import { useMutation } from "convex/react";',
                    'import { api } from "@/convex/_generated/api";',
                    'import { useAuth } from "@clerk/nextjs";',
                    'import { useState } from "react";',
                    'import { useRouter } from "next/navigation";',
                ]),
                deterministic: true,
                dependsOn: [],
            });
            pageParts.push("page-shell");
            // 3b. Auth guard (deterministic)
            parts.push({
                kind: "auth-guard",
                targetFile: pagePath,
                order: 1,
                prompt: "",
                preamble: authGuardPreamble(featureLabel),
                deterministic: true,
                dependsOn: ["page-shell"],
            });
            pageParts.push("auth-guard");
            // 3c. Form body (LLM — narrow scope)
            parts.push({
                kind: "form-body",
                targetFile: pagePath,
                order: 2,
                prompt: `Generate ONLY the form JSX and useState hooks for "${cap}" of feature "${featureLabel}".
Table: "${tableName}".
Requirements:
- useState hooks for each field (derive field names from the feature, NOT generic "title"/"description")
- A <form onSubmit={handleSubmit}> with labeled inputs
- A submit button with disabled state during submission
- Error display div
Output ONLY the form body code — no imports, no function declaration, no auth check.`,
                deterministic: false,
                dependsOn: ["page-shell", "auth-guard"],
            });
            pageParts.push("form-body");
            // 3d. Submit handler (LLM — narrow scope)
            parts.push({
                kind: "submit-handler",
                targetFile: pagePath,
                order: 3,
                prompt: `Generate ONLY the handleSubmit async function for "${cap}" of feature "${featureLabel}".
Table: "${tableName}", mutation: api.${tableName}.mutations.create.
Requirements:
- Check orgId and userId before proceeding
- Set isSubmitting state
- Call the mutation with form fields + orgId + createdBy: userId
- Redirect to "/${featureSlug}" on success
- Catch errors and set error state
Output ONLY the handleSubmit function — no imports, no component wrapper.`,
                deterministic: false,
                dependsOn: ["form-body"],
            });
            pageParts.push("submit-handler");
            // 3e. Validation (LLM — narrow scope, optional)
            parts.push({
                kind: "validation",
                targetFile: pagePath,
                order: 4,
                prompt: `Generate ONLY input validation logic for the "${cap}" form of "${featureLabel}".
Requirements:
- A validateForm() function that checks required fields
- Return { valid: boolean, errors: Record<string, string> }
- Check for empty strings, invalid formats as appropriate
Output ONLY the validation function — no imports, no component wrapper.`,
                deterministic: false,
                dependsOn: ["form-body"],
            });
            pageParts.push("validation");
            fileMap[pagePath] = pageParts;
        }
        else if (capabilityIsList(cap)) {
            const pagePath = `app/${featureSlug}/${capSlug}/page.tsx`;
            const pageParts = [];
            // Page shell (deterministic)
            parts.push({
                kind: "page-shell",
                targetFile: pagePath,
                order: 0,
                prompt: "",
                preamble: pageShellPreamble(featureLabel, `${featureSlug}-${capSlug}`, [
                    'import { useQuery } from "convex/react";',
                    'import { api } from "@/convex/_generated/api";',
                    'import { useAuth } from "@clerk/nextjs";',
                ]),
                deterministic: true,
                dependsOn: [],
            });
            pageParts.push("page-shell");
            // Auth guard (deterministic)
            parts.push({
                kind: "auth-guard",
                targetFile: pagePath,
                order: 1,
                prompt: "",
                preamble: authGuardPreamble(featureLabel),
                deterministic: true,
                dependsOn: ["page-shell"],
            });
            pageParts.push("auth-guard");
            // Data loader (partially deterministic + LLM for table body)
            parts.push({
                kind: "data-loader",
                targetFile: pagePath,
                order: 2,
                prompt: `Generate ONLY the useQuery hook call and the table/list JSX for "${cap}" of feature "${featureLabel}".
Table: "${tableName}", query: api.${tableName}.queries.list.
Requirements:
- useQuery call with orgId ? { orgId } : "skip"
- Table with header and body rows
- Column names derived from the feature (NOT generic "title"/"status")
Output ONLY the hook + JSX — no imports, no function declaration, no auth check.`,
                preamble: loadingStatePreamble(),
                deterministic: false,
                dependsOn: ["page-shell", "auth-guard"],
            });
            pageParts.push("data-loader");
            fileMap[pagePath] = pageParts;
        }
        else if (capabilityIsDetail(cap)) {
            const pagePath = `app/${featureSlug}/[id]/page.tsx`;
            const pageParts = [];
            // Page shell (deterministic)
            parts.push({
                kind: "page-shell",
                targetFile: pagePath,
                order: 0,
                prompt: "",
                preamble: pageShellPreamble(featureLabel, `${featureSlug}-detail`, [
                    'import { useQuery } from "convex/react";',
                    'import { api } from "@/convex/_generated/api";',
                    'import { useAuth } from "@clerk/nextjs";',
                    'import { useParams, useRouter } from "next/navigation";',
                    `import { Id } from "@/convex/_generated/dataModel";`,
                ]),
                deterministic: true,
                dependsOn: [],
            });
            pageParts.push("page-shell");
            // Auth guard (deterministic)
            parts.push({
                kind: "auth-guard",
                targetFile: pagePath,
                order: 1,
                prompt: "",
                preamble: authGuardPreamble(featureLabel),
                deterministic: true,
                dependsOn: ["page-shell"],
            });
            pageParts.push("auth-guard");
            // Data loader — detail variant
            parts.push({
                kind: "data-loader",
                targetFile: pagePath,
                order: 2,
                prompt: `Generate ONLY the useQuery + useParams hook calls and detail display JSX for "${cap}" of feature "${featureLabel}".
Table: "${tableName}", query: api.${tableName}.queries.get.
Requirements:
- const params = useParams(); const id = params.id as string;
- useQuery call with orgId ? { id: id as Id<"${tableName}">, orgId } : "skip"
- Loading skeleton, not-found state, detail display
- Back button using router.back()
Output ONLY the hook + JSX — no imports, no function declaration, no auth check.`,
                deterministic: false,
                dependsOn: ["page-shell", "auth-guard"],
            });
            pageParts.push("data-loader");
            fileMap[pagePath] = pageParts;
        }
    }
    // ── 4. Test (deterministic preamble + narrow LLM body) ──
    const testFile = `tests/${featureSlug}/${featureSlug}.test.ts`;
    parts.push({
        kind: "test",
        targetFile: testFile,
        order: 0,
        prompt: `Generate vitest test cases for "${featureLabel}".
The feature has table "${tableName}" with queries (list, get) and mutations (create, updateStatus).
Requirements:
- describe block named "${featureLabel}"
- Test: list query requires orgId argument
- Test: create mutation requires orgId and createdBy
- Test: updateStatus checks org ownership
- Use vi.fn() mocks, NOT real imports from the app
Output ONLY the describe block — no imports, no vi.mock (those are prepended).`,
        preamble: testPreamble(featureSlug),
        deterministic: false,
        dependsOn: [],
    });
    fileMap[testFile] = ["test"];
    return { featureSlug, tableName, parts, fileMap };
}
/**
 * Compose fragments for a single target file.
 * Deterministic parts use their preamble directly.
 * LLM parts use the generated code.
 * Order is respected within each file.
 */
export function composeFile(targetFile, fragments) {
    // Sort by order, filter to this file
    const relevant = fragments
        .filter((f) => f.part.targetFile === targetFile && f.success)
        .sort((a, b) => a.part.order - b.part.order);
    if (relevant.length === 0)
        return "";
    const sections = [];
    for (const frag of relevant) {
        // Deterministic parts: preamble is the complete output
        if (frag.part.deterministic && frag.part.preamble) {
            sections.push(frag.part.preamble);
        }
        else {
            // LLM parts: preamble (if any) + generated code
            if (frag.part.preamble) {
                sections.push(frag.part.preamble);
            }
            sections.push(frag.code);
        }
    }
    let composed = sections.join("\n");
    // Close the component function if this is a page file
    if (targetFile.endsWith("page.tsx") && composed.includes("export default function")) {
        // Count open/close braces to determine if we need a closing brace
        const opens = (composed.match(/\{/g) || []).length;
        const closes = (composed.match(/\}/g) || []).length;
        const missing = opens - closes;
        if (missing > 0) {
            composed += "\n" + "}".repeat(missing) + "\n";
        }
    }
    return composed;
}
/**
 * Get parts for a specific file, sorted by order.
 */
export function getPartsForFile(decomposed, targetFile) {
    return decomposed.parts
        .filter((p) => p.targetFile === targetFile)
        .sort((a, b) => a.order - b.order);
}
/**
 * Get all unique target files from a decomposed feature.
 */
export function getTargetFiles(decomposed) {
    return Object.keys(decomposed.fileMap);
}
/**
 * Check if all dependencies for a part have been satisfied.
 */
export function dependenciesSatisfied(part, completedKinds) {
    return part.dependsOn.every((dep) => completedKinds.has(dep));
}
